rules.exampleGood:
class Foo {
    private static final Logger LOG = Logger.getLogger(Foo.class.getName());
    void bar() {
        try {
            /* whatever */
        } catch (Exception e) {
            LOG.log(Level.SEVERE, "exception", e);
        }
    }
}

